+    let mut outputs = [FfiBuffer::zeroed(vec![0, 5], DType::F64).unwrap()];
+
+    call.invoke(&reg, &[input], &mut outputs).unwrap();
+    assert_eq!(outputs[0].size(), 0);
+    assert!(outputs[0].as_bytes().is_empty());
+}
